@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            <div class="infinite-scroll-spinner"></div>
        </div>
    }
</div>

@code {
    /// <summary>The collection of items to display.</summary>
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    /// <summary>Whether more items are available to load.</summary>
    [Parameter]
    public bool HasMore { get; set; }

    /// <summary>Callback invoked when the user scrolls near the bottom.</summary>
    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    /// <summary>Template for rendering each item.</summary>
    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotnetRef;
    private bool isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-2cd0cd8932c547b3bb7af0ff7d77cd35/Components/InfiniteScrollList.razor.js");
            dotnetRef = DotNetObjectReference.Create(this);
        }

        if (HasMore && module is not null)
        {
            await module.InvokeVoidAsync("observe", sentinelRef, dotnetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore) return;

        isLoading = true;
        await OnLoadMore.InvokeAsync();
        isLoading = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            try { await module.InvokeVoidAsync("disconnect"); } catch (JSDisconnectedException) { }
            try { await module.DisposeAsync(); } catch (JSDisconnectedException) { }
        }
        dotnetRef?.Dispose();
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid #dee2e6;
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.75s linear infinite;
}

@keyframes infinite-scroll-spin {
    to { transform: rotate(360deg); }
}

